import React from "react";
import ReactDOM from "react-dom/client";
import Header from "./Header";
import Home from "./Home";

import "./Header.css";
import "./Home.css";

// Mount su #Header
const headerRoot = ReactDOM.createRoot(document.getElementById("Header"));
headerRoot.render(<Header className="header" />);

// Mount su #Home
const homeRoot = ReactDOM.createRoot(document.getElementById("Home"));
homeRoot.render(<Home className="home" />);
